mapper.select:
SELECT id, user_id, plate_number, vehicle_type, is_special, remark, create_time, update_time
FROM vehicle
WHERE id = #{id}

mapper.update:
UPDATE vehicle
SET plate_number = #{plateNumber},
    vehicle_type = #{vehicleType},
    is_special = #{isSpecial},
    remark = #{remark}
WHERE id = #{id}
